c
// Offset: 0x00 - Function Entry
void connection_close(tcp_server_t *s, connection_t *c) {
if (c->n_in_flight > 0) {
c->cancel_requested = true;
c->state = CONN_CANCELLING;
// IORING_OP_ASYNC_CANCEL (28)
// sqe->addr = (uint64_t)c->fd;
// sqe->cancel_flags = IORING_ASYNC_CANCEL_ALL;
submit_async_cancel(s->ring, c->fd,
IORING_ASYNC_CANCEL_ALL);
return; // Defer close() until CQE
}
// Critical Section: Ensure n_in_flight == 0
close(c->fd);
c->fd = -1;
c->state = CONN_CLOSED;
}
